import{_ as s,c as a,o as i,aj as t}from"./chunks/framework.BlveriQe.js";const g=JSON.parse('{"title":"Quick Start","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/template-app.md","filePath":"getting-started/template-app.md"}'),n={name:"getting-started/template-app.md"};function o(l,e,p,r,d,h){return i(),a("div",null,[...e[0]||(e[0]=[t(`<h1 id="quick-start" tabindex="-1">Quick Start <a class="header-anchor" href="#quick-start" aria-label="Permalink to “Quick Start”">​</a></h1><p>The fastest way to build on Primitive is to start from an official template. Primitive supports multiple platforms as first-class citizens — there&#39;s a <strong>web template</strong> (Vue + TypeScript + Tailwind) and an <strong>iOS template</strong> (Swift + SwiftUI). Both give you a working app in minutes: authentication, local-first data storage, real-time sync, and dev tooling. (Templates are optional — the clients are plain libraries; see <a href="./authentication.html#using-the-client-directly">Using the Client Directly</a>.)</p><h2 id="_1-create-your-app" tabindex="-1">1. Create Your App <a class="header-anchor" href="#_1-create-your-app" aria-label="Permalink to “1. Create Your App”">​</a></h2><p>Run the installer, replacing <code>my-app</code> with your desired app name:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> create-primitive-app</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-app</span></span></code></pre></div><p>It asks which platform you&#39;re building for — web or iOS — or pass <code>--platform web</code> / <code>--platform ios</code> to skip the prompt. (Building for iOS requires macOS with Xcode 15+ and <code>brew install xcodegen</code>; an Apple Developer account is only needed for physical devices, TestFlight, and the App Store — the simulator runs unsigned.)</p><p>The installer will:</p><ul><li>Prompt you to sign in to your Primitive account (if not already authenticated)</li><li>Create a new app on the Primitive servers</li><li>Download and configure the platform&#39;s template</li><li>Initialize a Git repository and create an initial commit</li><li>Install dependencies (<code>pnpm</code> for web, <code>swift package resolve</code> for iOS)</li></ul><h2 id="_2-run-it" tabindex="-1">2. Run It <a class="header-anchor" href="#_2-run-it" aria-label="Permalink to “2. Run It”">​</a></h2><div class="vp-code-group"><div class="tabs"><input type="radio" name="group-49" id="tab-50" checked><label data-title="Web (Vue)" for="tab-50">Web (Vue)</label><input type="radio" name="group-49" id="tab-51"><label data-title="iOS (SwiftUI)" for="tab-51">iOS (SwiftUI)</label></div><div class="blocks"><div class="language-bash active"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-app</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># → http://localhost:5173</span></span></code></pre></div><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-app</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./run-ios.sh</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># regenerates the Xcode project, runs model codegen, builds, and</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># launches the simulator</span></span></code></pre></div></div></div><p>To run on a physical iPhone or iPad, set up <a href="./deploying-to-production.html#_1-signing-and-team-id">signing</a> once, then <code>./run-ios.sh --device</code>. You need a paired iPhone connected over USB (<code>xcrun devicectl list devices</code> should show it as <code>paired</code>); the script auto-picks the first paired device, builds with <code>-allowProvisioningUpdates</code> so Xcode requests provisioning profiles for you, installs via <code>devicectl</code>, and launches with <code>--console</code> so <code>print</code> and NSLog output stream to your terminal.</p><p><strong>Congratulations!</strong> You now have a working Primitive app with:</p><ul><li>Authentication with a drop-in login flow (OAuth, Magic Link, OTP, and Passkeys on web; one-time email code, Google and Apple sign-in, and Passkeys on iOS)</li><li>Local-first data storage with real-time sync</li><li>Server-side databases with access control</li><li>Blob storage for files and images</li><li>Built-in dev tools (Document Explorer, Test Harness, and Blob Explorer on web; the Debug Inspector on iOS)</li><li>CLI for managing workflows, prompts, integrations, and more</li></ul><h2 id="_3-push-to-a-remote-repository-optional" tabindex="-1">3. Push to a Remote Repository (Optional) <a class="header-anchor" href="#_3-push-to-a-remote-repository-optional" aria-label="Permalink to “3. Push to a Remote Repository (Optional)”">​</a></h2><p>The scaffold initializes a Git repository and creates an initial commit for you. To push to a remote like GitHub:</p><ol><li><p>Create a new repository on <a href="https://github.com/new" target="_blank" rel="noreferrer">GitHub</a> (don&#39;t initialize with README, .gitignore, or license)</p></li><li><p>Add the remote and push:</p></li></ol><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> remote</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> origin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/your-username/my-app.git</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> branch</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -M</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> main</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> push</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> origin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> main</span></span></code></pre></div><h2 id="setting-up-google-sign-in-optional" tabindex="-1">Setting Up Google Sign In (Optional) <a class="header-anchor" href="#setting-up-google-sign-in-optional" aria-label="Permalink to “Setting Up Google Sign In (Optional)”">​</a></h2><p>Google OAuth is optional. The template&#39;s login shows a &quot;Sign in with Google&quot; button automatically once it&#39;s configured — create the OAuth client in Google Cloud Console, enter its credentials in the Admin Console, and enable the provider. The full walkthrough is in <a href="./authentication.html#setting-up-google-oauth-optional">Setting Up Google OAuth</a>.</p><h2 id="what-s-in-the-template" tabindex="-1">What&#39;s in the Template? <a class="header-anchor" href="#what-s-in-the-template" aria-label="Permalink to “What&#39;s in the Template?”">​</a></h2><p>Both templates share the same shape: app config, data model schemas with codegen, UI scaffolding around the platform&#39;s login flow, and agent guides for AI coding assistants.</p><div class="vp-code-group"><div class="tabs"><input type="radio" name="group-122" id="tab-123" checked><label data-title="Web (Vue)" for="tab-123">Web (Vue)</label><input type="radio" name="group-122" id="tab-124"><label data-title="iOS (SwiftUI)" for="tab-124">iOS (SwiftUI)</label></div><div class="blocks"><div class="language-text active"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>my-app/</span></span>
<span class="line"><span>├── src/</span></span>
<span class="line"><span>│   ├── assets/         # Static images and assets</span></span>
<span class="line"><span>│   ├── components/     # Vue components (organized by area)</span></span>
<span class="line"><span>│   ├── components/ui/  # shadcn-vue base components</span></span>
<span class="line"><span>│   ├── composables/    # Vue composables</span></span>
<span class="line"><span>│   ├── config/         # Environment configuration</span></span>
<span class="line"><span>│   ├── layouts/        # Page layout components</span></span>
<span class="line"><span>│   ├── lib/            # Business logic (pure TypeScript)</span></span>
<span class="line"><span>│   ├── models/         # js-bao data models (models.toml + auto-generated *.generated.ts)</span></span>
<span class="line"><span>│   ├── pages/          # Route components</span></span>
<span class="line"><span>│   ├── router/         # Vue Router setup</span></span>
<span class="line"><span>│   └── tests/          # Test harness test files</span></span>
<span class="line"><span>├── docs/               # Agent guides for AI coding assistants</span></span>
<span class="line"><span>├── .env                # Development environment variables</span></span>
<span class="line"><span>├── .env.production     # Production environment variables</span></span>
<span class="line"><span>└── wrangler.toml       # Deployment config</span></span></code></pre></div><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>my-app/</span></span>
<span class="line"><span>├── Sources/PrimitiveAppTemplate/</span></span>
<span class="line"><span>│   ├── PrimitiveAppTemplateApp.swift   # @main entry — owns the app state</span></span>
<span class="line"><span>│   ├── TemplateAppState.swift          # PrimitiveAppState subclass: client lifecycle, documents</span></span>
<span class="line"><span>│   ├── Views/                          # SwiftUI views (ContentView wraps AuthGateView)</span></span>
<span class="line"><span>│   └── Models/</span></span>
<span class="line"><span>│       ├── models.toml                 # Your data model schemas</span></span>
<span class="line"><span>│       └── Generated/                  # swift-bao-codegen output</span></span>
<span class="line"><span>├── docs/                               # Agent guides for AI coding assistants</span></span>
<span class="line"><span>├── Package.swift                       # SwiftPM manifest (pulls in PrimitiveApp)</span></span>
<span class="line"><span>├── primitive.json                      # App ID + server URLs — bundled and read at launch</span></span>
<span class="line"><span>├── project.yml                         # xcodegen source of truth — edit this, regenerate the xcodeproj</span></span>
<span class="line"><span>├── run-ios.sh                          # Build + launch (simulator or device)</span></span>
<span class="line"><span>└── fastlane/                           # TestFlight + App Store lanes</span></span></code></pre></div></div></div><p>Key configuration files:</p><table tabindex="0"><thead><tr><th></th><th>Web (Vue)</th><th>iOS (SwiftUI)</th></tr></thead><tbody><tr><td>App config</td><td><code>src/config/envConfig.ts</code> (API URLs, App ID)</td><td><code>primitive.json</code> (App ID + server URLs)</td></tr><tr><td>Data models (start here!)</td><td><code>src/models/models.toml</code> — run <code>pnpm codegen</code> after editing</td><td><code>Sources/…/Models/models.toml</code> — codegen is wired into both build paths</td></tr><tr><td>Agent guides</td><td><code>docs/</code></td><td><code>docs/</code></td></tr></tbody></table><p>On iOS, the <code>PrimitiveApp</code> package does the heavy lifting: <code>PrimitiveAppState</code> owns the <code>JsBaoClient</code> lifecycle (your app subclasses it, like the template&#39;s <code>TemplateAppState</code>), <code>AuthGateView</code> presents <code>PrimitiveLoginView</code> until the user is signed in and connected, and <code>BaoDataLoader</code> binds queries to SwiftUI views — the counterparts of the web template&#39;s client service, <code>PrimitiveLogin</code>, and <code>useJsBaoDataLoader</code>. <code>appState.initialize()</code> reads <code>primitive.json</code>, creates the client, attaches the auth manager, and in dev mode auto-signs you in with your CLI token from <code>~/.primitive/credentials.json</code> so you don&#39;t log in on every rebuild.</p><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to “Next Steps”">​</a></h2><p>Now that your app is running:</p><ol><li><strong><a href="./choosing-your-data-model.html">Choosing Your Data Model</a></strong> — Decide between documents, databases, or both</li><li><strong><a href="./working-with-documents.html">Working with Documents</a></strong> — Local-first collaborative data</li><li><strong><a href="./working-with-databases.html">Working with Databases</a></strong> — Server-side structured storage</li><li><strong><a href="./authentication.html">Authentication</a></strong> — Set up sign-in methods</li><li><strong><a href="./devtools.html">Dev Tools</a></strong> — Inspect data, manage files, run tests</li><li><strong><a href="./deploying-to-production.html">Deploying to Production</a></strong> — Deploy your app to production</li></ol>`,28)])])}const u=s(n,[["render",o]]);export{g as __pageData,u as default};
